formulas.expression:
IF({!View_Assets_Without_Any_Target} = True, 'Assets Without Target',
    IF({!Select_A_Year} = Null, 'All Assets',
                       'Assets With Target In ' + {!Select_A_Year}
))

IF( ISBLANK({!Choose_Snapshot}),
/* No snapshot selected → return no records */ "SELECT Id, Name FROM pro_Asset_Target_Snapshot_Item__c WHERE Id = null",
/* Snapshot selected → return related snapshot items */ "SELECT Id, Name, pro_Asset__c, pro_Asset_Id__c, pro_Asset_Name__c, pro_Asset_In_Deal__c, pro_Asset_In_Deal_Id__c, pro_Asset_In_Deal_Name__c, " & "pro_Asset_Target_Snapshot__c, pro_Contract__c, pro_Contract_Id__c, pro_Contract_Name__c, pro_Likely_Outcome__c, pro_LOId_Deal_Type__c, " & "pro_Marketing_Trading__c, pro_Progress__c, pro_Target_End_Date__c, pro_Target_Forecast__c, pro_Target_Forecast_Id__c, pro_Target_Forecast_Name__c, " & "pro_Target_Reached__c, pro_Target_Reached_Id__c, pro_Target_Reached_Name__c " & "FROM pro_Asset_Target_Snapshot_Item__c " & "WHERE pro_Asset_Target_Snapshot__r.Name = '" & {!Choose_Snapshot} & "'" )

IF( NOT(ISBLANK({!Select_A_Year})),
/* Year is selected */ IF( ISBLANK({!Select_An_Outcome}) || {!Select_An_Outcome} = "All",
/* All outcomes except Target Cancelled and Moved To Trading */ {!varTargetQueryFields} & " FROM pro_Asset_Target_Audit__c" & " WHERE pro_Target_Year__c = '" & TEXT(VALUE({!Select_A_Year})) & "'" & " AND pro_Progress__c NOT IN ('Target Cancelled','Moved To Trading')" & " ORDER BY pro_Target_End_Date__c ASC",
/* Specific outcomes */ IF( {!Select_An_Outcome} = "Open", {!varTargetQueryFields} & " FROM pro_Asset_Target_Audit__c" & " WHERE pro_Target_Year__c = '" & TEXT(VALUE({!Select_A_Year})) & "'" & " AND pro_Progress__c IN ('Open','Open - Target Date Exceeded')" & " ORDER BY pro_Target_End_Date__c ASC",
IF( {!Select_An_Outcome} = "Achieved", /* Achieved — filter where Progress contains 'Achieved', and apply Achieved_By logic */ {!varTargetQueryFields} & " FROM pro_Asset_Target_Audit__c" & " WHERE pro_Target_Year__c = '" & TEXT(VALUE({!Select_A_Year})) & "'" & " AND pro_Progress__c LIKE '%Achieved%'" & IF( ISBLANK({!Achieved_By}), "", IF( {!Achieved_By} = "Marketing", " AND pro_Marketing_Trading__c LIKE '%Marketing%'", IF( {!Achieved_By} = "Trading", " AND pro_Marketing_Trading__c LIKE '%Trading%'", "" ) ) ) & " ORDER BY pro_Target_End_Date__c ASC",
/* Moved To Trading */ {!varTargetQueryFields} & " FROM pro_Asset_Target_Audit__c" & " WHERE pro_Target_Year__c = '" & TEXT(VALUE({!Select_A_Year})) & "'" & " AND pro_Moved_To_Trading__c = True" & " ORDER BY pro_Target_End_Date__c ASC" ) ) ),
/* No year selected → return 0 records */ "SELECT Name, Id FROM pro_Asset_Target_Audit__c WHERE Id = NULL" )

IF(
    {!View_Target_Snapshot} = TRUE,
    /* Snapshot view */
    "Target Snapshot",

    IF(
        ISBLANK({!Select_A_Year}),
        /* No year selected */
        "Select A Year",

        /* Year selected — decide message based on outcome */
        IF(
            {!Select_An_Outcome} = "Open",
            {!Select_A_Year} & " Targets Open" ,

            IF(
                {!Select_An_Outcome} = "Achieved",
                {!Select_A_Year} & " Targets Achieved "  ,

                IF(
                    {!Select_An_Outcome} = "Moved To Trading",
                    {!Select_A_Year} & " Targets Moved To Trading " ,

                    /* Fallback — just show total for year */
                    {!Select_A_Year} & ' Targets'
                )
            )
        )
    )
)

IF(
    {!View_Target_Snapshot} = TRUE,
    /* Only return records where snapshot date exists */
    {!varTargetQueryFields} & 
    " FROM pro_Asset_Target_Audit__c" &
    " WHERE pro_Target_Snapshot_Date__c != NULL" &
    " ORDER BY pro_Target_Snapshot_Date__c ASC",

    /* If user cannot view snapshot → return 0 records */
    "SELECT Name, Id FROM pro_Asset_Target_Audit__c WHERE Id = NULL"
)
